payload.raw:
{
  "layout": "milestone-list",
  "title": "创新设计：技术路线",
  "subtitle": "五阶闭环实施路径",
  "events": [
    {
      "date": "阶段一",
      "title": "柔性传感材料研发",
      "description": "基于仿水膜-鱼网结构设计液态金属基导电薄膜与聚氨酯复合材料，优化微结构工艺与信号标定。"
    },
    {
      "date": "阶段二",
      "title": "混合传感架构开发",
      "description": "构建融合光纤传感与惯性测量单元的硬件系统，实现0.1mm级空间分辨率与高鲁棒性。"
    },
    {
      "date": "阶段三",
      "title": "手势识别算法训练",
      "description": "开发轻量化分层CNN-LSTM模型，结合时序滑动窗口分割，提升识别准确率至98.2%以上。"
    },
    {
      "date": "阶段四",
      "title": "多模态系统集成",
      "description": "集成统一时空对齐协议栈，嵌入压力/温度反馈单元，构建感知-意图-反馈闭环交互系统。"
    },
    {
      "date": "阶段五",
      "title": "场景验证与优化",
      "description": "依托H-Box全息舱等合作平台，开展工业远程操控与虚拟实训场景测试，进行用户体验迭代优化。"
    }
  ]
}

